import com.google.common.collect.ListMultimap;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Collection;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class RekenElementBeheer {
    public static final int EXTENSIE_APO = 999;
    public static final BigDecimal AANSTELLING_9999 = BigDecimal.valueOf(9999);
    public static final int CODE_1001 = 1001;
    public static final int EXTENSIE_99 = 99;
    private static final LocalDate GRENS_GENEREREN_CODE_PENS_ANTWERPEN = new LocalDate(2021, 4, 1);
    private static final int LOONCODE_MOBILITEITS_BUDGET = 29;

    public void vormRekenElementen(
            Opdracht opdracht, RekenHoofdArtikelKey rekenHoofdArtikelKey, ArtikelLoonElementManager manager,
            RekenTijd rekenTijd, MaandTotaal1 maandTotaal1, ListMultimap<RekenElementenBoekingKey, RekenElement> opdrachtNrLooncodeToRekenElementen,
            LocalDateInterval maandTotaalPeriode, boolean nulResultaat, LoonCodeManager loonCodeManager, ConstantManager constantManager) {
        Collection<LoonElement> rmElementen = getRekenHoofdArtikelElementenKwartaal(rekenHoofdArtikelKey, manager, maandTotaal1.getAard());
        Map<RekenElementenBoekingKey, RekenElement> nlpElementenMap = new HashMap<>();
        MoneyMap<RekenElementenBoekingKey> elementBrutoMap = new HashMoneyMap<>();
        MoneyMap<RekenElementenBoekingKey> elementBassiMap = new HashMoneyMap<>();
        Set<RekenElementenBoekingKey> saveNulSet = new HashSet<>();
        for (LoonElement rmElement : rmElementen) {
            processElement(opdracht, rekenTijd, opdrachtNrLooncodeToRekenElementen, maandTotaalPeriode, nulResultaat, loonCodeManager, constantManager, elementBrutoMap,
                    elementBassiMap, saveNulSet, rmElement);
        }
        Set<RekenElementenBoekingKey> keys = new HashSet<>(elementBrutoMap.keySet());
        keys.addAll(elementBassiMap.keySet());
        keys.addAll(opdrachtNrLooncodeToRekenElementen.keySet());

        for (RekenElementenBoekingKey key : keys) {
            processRekenEkementenBoekingKey(maandTotaal1, opdrachtNrLooncodeToRekenElementen, nlpElementenMap, elementBrutoMap, elementBassiMap, saveNulSet, key);
        }

        maandTotaal1.setRekenElementen(new HashSet<>(nlpElementenMap.values()));
    }

    private void processElement(
            Opdracht opdracht, RekenTijd rekenTijd, ListMultimap<RekenElementenBoekingKey, RekenElement> opdrachtNrLooncodeToRekenElementen,
            LocalDateInterval maandTotaalPeriode, boolean nulResultaat, LoonCodeManager loonCodeManager, ConstantManager constantManager,
            MoneyMap<RekenElementenBoekingKey> elementBrutoMap, MoneyMap<RekenElementenBoekingKey> elementBassiMap, Set<RekenElementenBoekingKey> saveNulSet,
            LoonElement rmElement) {
        AardKodeExtensie loonCode = rmElement.getAardKodeExtensie();
        if (!loonCode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode()) && !isBijsturingConversie(rmElement.getAardKodeExtensie())) {
            LocalDateInterval rekenLijnPeriode = rmElement.getPropertyUnchecked(RekenChainKey.REKENLIJN_PERIODE_KEY);
            AardRekenelement typeBoeking = rmElement.getPropertyUnchecked(RekenChainKey.REKENLIJN_TYPE_BOEKING_KEY);
            Integer referentieJaar = getReferentieJaarNonNull(rmElement);
            LocalDateInterval interval = bepaalInterval(rekenTijd, maandTotaalPeriode, rekenLijnPeriode);

            RekenElementenBoekingKey key =
                    new RekenElementenBoekingKey(opdracht.getOpdrachtnr(), loonCode, referentieJaar, interval.getStart(), interval.getEnd(),
                            typeBoeking);
            List<RekenElement> bestaandeRmElementen = opdrachtNrLooncodeToRekenElementen.get(key);

            Money elementBruto = rmElement.getPropertyMoney(RekenBrutoKey.BRUTO_MAANDLOON_KEY);
            Money elementBasSi = rmElement.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);

            Money basisSiBestaand = MaandTotaalUtil.maakElementSomBasisSocialeInhoudingen(bestaandeRmElementen);
            if (rekenTijd.isApo && loonCode.getExtensie() == EXTENSIE_APO && basisSiBestaand.signum() == 0) {
                elementBasSi = Money.ZERO;
            }

            if (loonCode.behoortTotGroep(LooncodeGroepKeyStrings.ERKENT_PREMIE_OF_WG_BIJDR_GROEPSVERZ_KEY)) {
                elementBruto = elementBasSi;
            }

            elementBrutoMap.addToMoney(key, elementBruto);
            elementBassiMap.addToMoney(key, elementBasSi);

            processPens2Antwerpen(rekenTijd, loonCodeManager, constantManager, elementBassiMap, rmElement, key);

            BigDecimal aanstelling = rmElement.getOpper().getRszppo().getAanstelling();
            boolean saveNul = aanstelling.signum() != 0 && !aanstelling.equals(AANSTELLING_9999) && nulResultaat;
            if (saveNul) {
                saveNulSet.add(key);
            }
        }
    }

    private static Integer getReferentieJaarNonNull(LoonElement rmElement) {
        Integer referentieJaar = rmElement.getReferentieJaar();
        if (referentieJaar == null) {
            referentieJaar = 0;
        }
        return referentieJaar;
    }

    private static LocalDateInterval bepaalInterval(RekenTijd rekenTijd, LocalDateInterval maandTotaalPeriode, LocalDateInterval rekenLijnPeriode) {
        LocalDateInterval interval;
        if (rekenTijd.isApo) {
            interval = maandTotaalPeriode;
        } else {
            interval = rekenLijnPeriode;
        }
        return interval;
    }

    private static void processPens2Antwerpen(
            RekenTijd rekenTijd, LoonCodeManager loonCodeManager, ConstantManager constantManager, MoneyMap<RekenElementenBoekingKey> elementBassiMap,
            LoonElement rmElement, RekenElementenBoekingKey key) {
        if (heeftPens2Antwerpen(constantManager, rekenTijd)) {
            splitsBedragOpAparteLoonCode(elementBassiMap, RekenBasisRszKey.BASIS_TWEEDE_PENSIOENPIJLER_KEY,
                    CodeExtensie.ANTWERPEN_2DE_PENSIOENPIJLER_ONDER_GRENS,
                    rmElement, key, loonCodeManager);
            splitsBedragOpAparteLoonCode(elementBassiMap, RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY,
                    CodeExtensie.ANTWERPEN_2DE_PENSIOENPIJLER_BOVEN_GRENS,
                    rmElement, key, loonCodeManager);
        }
    }

    private void processRekenEkementenBoekingKey(
            MaandTotaal1 maandTotaal1, ListMultimap<RekenElementenBoekingKey, RekenElement> opdrachtNrLooncodeToRekenElementen,
            Map<RekenElementenBoekingKey, RekenElement> nlpElementenMap, MoneyMap<RekenElementenBoekingKey> elementBrutoMap,
            MoneyMap<RekenElementenBoekingKey> elementBassiMap, Set<RekenElementenBoekingKey> saveNulSet, RekenElementenBoekingKey key) {
        List<RekenElement> bestaandeRmElementen = opdrachtNrLooncodeToRekenElementen.get(key);
        Money brutoBestaand = MaandTotaalUtil.maakElementSomBruto(bestaandeRmElementen);
        Money elementBruto = elementBrutoMap.getMoney(key);
        elementBruto = elementBruto.subtract(brutoBestaand);

        Money basisSiBestaand = MaandTotaalUtil.maakElementSomBasisSocialeInhoudingen(bestaandeRmElementen);
        Money elementBasSi = elementBassiMap.getMoney(key);
        elementBasSi = elementBasSi.subtract(basisSiBestaand);

        RekenElement nlpElement = nlpElementenMap.get(key);
        if (nlpElement != null) {
            elementBruto = elementBruto.add(nlpElement.getBruto());
            elementBasSi = elementBasSi.add(nlpElement.getBasisSocialeInhoudingen());
            nlpElementenMap.remove(key);
        }
        if (elementBruto.signum() != 0 || elementBasSi.signum() != 0 || saveNulSet.contains(key) || rekenBedragZeroOpslaan(key)) {
            nlpElement = maakRekenElement(key, elementBruto, elementBasSi);
            nlpElement.setMaandTotaal1(maandTotaal1);
            nlpElementenMap.put(key, nlpElement);
        }
    }

    private boolean rekenBedragZeroOpslaan(RekenElementenBoekingKey key) {
        return key.getRekenElementenKey().getCode() == LOONCODE_MOBILITEITS_BUDGET;
    }

    protected RekenElement maakRekenElement(RekenElementenKey rekenElementKey, Money bruto, Money bassi, AardRekenelement typeBoeking) {
        RekenElement rekenElement = new RekenElementPO();

        rekenElement.setBeginDatum(rekenElementKey.getBeginDatum());
        rekenElement.setEindDatum(rekenElementKey.getEindDatum());
        rekenElement.setTijdperk(rekenElementKey.getTijdperk());
        rekenElement.setAard(rekenElementKey.getAard());
        rekenElement.setCode(rekenElementKey.getCode());
        rekenElement.setExtensie(rekenElementKey.getExtensie());

        rekenElement.setBruto(bruto);
        rekenElement.setBasisSocialeInhoudingen(bassi);

        rekenElement.setVakantieReferentiejaar(rekenElementKey.getReferentieJaar());
        rekenElement.setTypeBoeking(typeBoeking.getCode());

        return rekenElement;
    }

    protected RekenElement maakRekenElement(RekenElementenBoekingKey key, Money bruto, Money bassi) {
        RekenElementenKey rekenElementKey = key.getRekenElementenKey();
        return maakRekenElement(rekenElementKey, bruto, bassi, key.getTypeBoeking());
    }

    private static boolean heeftPens2Antwerpen(ConstantManager constantManager, RekenTijd rekenTijd) {
        int typeBijdrage = constantManager.getByCodeDatum(Konstanten.KST_TYPE_BIJDRAGE_PENS2, rekenTijd.beginDatum).getInteger();
        return typeBijdrage == PensioenPijler2TypeBijdrage.ANTWERPEN.getCode() &&
                GRENS_GENEREREN_CODE_PENS_ANTWERPEN.compareTo(rekenTijd.beginDatum) <= 0;
    }

    private static void splitsBedragOpAparteLoonCode(
            MoneyMap<RekenElementenBoekingKey> elementBassiMap, MoneyKey moneyKey, CodeExtensie codeExtensie, LoonElement rmElement,
            RekenElementenBoekingKey key,
            LoonCodeManager loonCodeManager) {
        Money basisPens2 = rmElement.getPropertyMoney(moneyKey);
        AardKodeExtensie loonCodePens2OnderGrens =
                loonCodeManager.getByTake(AkeTijdperk.DMFAPPL.getCode(), AardKodeExt.V_KODE_EXT.getCode(), codeExtensie.getCode(), codeExtensie.getExtensie());
        RekenElementenKey reKey = key.getRekenElementenKey();
        RekenElementenBoekingKey keyPens2OnderGrens =
                new RekenElementenBoekingKey(reKey.getOpdrachtNr(), loonCodePens2OnderGrens, reKey.getReferentieJaar(), reKey.getBeginDatum(), reKey.getEindDatum(),
                        key.getTypeBoeking());
        elementBassiMap.addToMoney(keyPens2OnderGrens, basisPens2);
    }

    protected boolean isBijsturingConversie(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getCode() == CODE_1001 && aardKodeExtensie.getExtensie() == EXTENSIE_99;
    }

    public static Collection<LoonElement> getRekenHoofdArtikelElementenKwartaal(
            RekenHoofdArtikelKey rekenHoofdArtikelKey, ArtikelLoonElementManager manager, AardMaandtotaal aardMaandtotaal) {
        List<LoonElement> rmElementen = new ArrayList<>();
        if (aardMaandtotaal == AardMaandtotaal.KWARTAAL) {
            addRekenElementenKwartaal(rekenHoofdArtikelKey, manager, rmElementen);
        } else {
            rmElementen.addAll(manager.getRekenHoofdArtikelElementen(rekenHoofdArtikelKey));
        }
        return rmElementen;
    }

    private static void addRekenElementenKwartaal(RekenHoofdArtikelKey rekenHoofdArtikelKey, ArtikelLoonElementManager manager, List<LoonElement> rmElementen) {
        Quarter kwartaal = new Quarter(rekenHoofdArtikelKey.getBeginDatum());
        LocalDate kwartaalStart = kwartaal.getStart();
        addRekenElementenKwartaalMaand(kwartaalStart, rekenHoofdArtikelKey, rmElementen, manager);
        int teller = 1;
        addRekenElementenKwartaalMaand(kwartaalStart.plusMonths(teller), rekenHoofdArtikelKey, rmElementen, manager);
        teller++;
        addRekenElementenKwartaalMaand(kwartaalStart.plusMonths(teller), rekenHoofdArtikelKey, rmElementen, manager);
    }

    private static void addRekenElementenKwartaalMaand(
            LocalDate maandStart, RekenHoofdArtikelKey rekenHoofdArtikelKey, List<LoonElement> rmElementen, ArtikelLoonElementManager manager) {
        RekenHoofdArtikelKey maandKey = new RekenHoofdArtikelKey(rekenHoofdArtikelKey, maandStart);
        rmElementen.addAll(manager.getRekenHoofdArtikelElementen(maandKey));
    }
}
